var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"치후유가 파티룸을 선택할 줄은 몰랐어.","JPN":"まさか千冬がパーティールームを選ぶなんてね。","ENG":"I did not expect you to choose the rental recreation room.","TWN":"千冬竟然會選擇派對包廂。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"후후. 여유를 가지는 것이 좋다고 생각한 것뿐입니다.","JPN":"ふふ。のんびりできる方が良いと思っただけです。","ENG":"Haha. I just thought it would be good for us to take a little break.","TWN":"呵呵，只是覺得需要放鬆一下而已。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"게다가 시끄러운 것보단 둘이서 불꽃놀이를 감상하는 것도 좋다고 생각했거든요.","JPN":"それに、騒がしいのよりも、二人で静かに花火を鑑賞できる方が良いと思いました。","ENG":"I also thought it would be better for us to watch the fireworks in peace, rather than in a crowd.","TWN":"而且與其吵吵鬧鬧，我更喜歡二個人一起看煙火。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"어쩌면 드레스를 입으니 들뜬 걸지도 모르겠습니다.","JPN":"もしかすると、ドレスを着て心が浮かれていたのかもしれません。","ENG":"Perhaps I am overly thrilled from wearing this dress.","TWN":"或許是因為穿上這件禮服讓我有點興奮吧。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"나는 기쁘기만 한걸.","JPN":"私は嬉しかったわ。","ENG":"I am glad, though.","TWN":"我覺得很開心。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"치후유가 조금 더 표현을 해줬으면 했거든.","JPN":"千冬にもっと色々表現してほしかったから。","ENG":"I wish you would express yourself more.","TWN":"我一直希望千冬能多表達一些情感，"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"우리 나이 또래들처럼 말이야.","JPN":"年相応にね。","ENG":"Like the other girls of our age.","TWN":"像我們這個年紀的孩子一樣。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"언니……","JPN":"姉さん……","ENG":"Sis...","TWN":"姊姊……"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"오붓하게 둘이 있게 됐네? 뭐라도 좀 먹을까?","JPN":"こぢんまりと二人きりになったわね。何か食べようか？","ENG":"I guess it is just us two now. Would you like to eat something?","TWN":"難得只有我們二個，要去吃點什麼嗎？"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"가능하다면 빙수를 먹을 수 있을까요?","JPN":"できれば、かき氷を食べてもいいでしょうか。","ENG":"Would it be possible to eat shaved ice?","TWN":"可以的話，我想吃刨冰。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"빙수? 안되는 건 아니지만, 이유가 궁금한데?","JPN":"かき氷？　ダメってわけではないけど、理由が気になるわ。","ENG":"Shaved ice? It is not impossible, but why?","TWN":"刨冰？不是不行，只是好奇為什麼？"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"그건……","JPN":"それは……","ENG":"That is...","TWN":"因為……"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"어렸을 적의 추억이…… 떠올랐기 때문입니다.","JPN":"小さい頃の思い出が……思い浮かんだからです。","ENG":"That is because... I was reminded of a childhood memory.","TWN":"這會讓我想起小時候……"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"어렸을 적…… 추억?","JPN":"小さい頃の……思い出？","ENG":"Childhood... memory?","TWN":"想起……小時候？"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"네. 언니께서 힘들 때마다 수련중인 저를 찾아오신 걸 기억하시는지요?","JPN":"はい。姉さんが辛い時、修練中の私を訪ねてきたことを覚えていますか？","ENG":"Yes. Do you remember when you would visit me every time you were stressed?","TWN":"是的。姊姊還記得，每次你遇到困難時，你都會來我修練的地方找我嗎？"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"응. 길을 잃고 헤매느니, 치후유를 찾아오라고 했지.","JPN":"うん。道に迷うくらいなら自分を訪ねるように言われて。","ENG":"Yes. You said I should come to you instead of wandering around and getting lost.","TWN":"記得。你說過，遇到困難就去找你。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"어른들이 찾지 못하는 수련 장소들이 많다고 말이야.","JPN":"大人も探せないような修練場が多いんだって。","ENG":"You said you knew a lot of training grounds that the adults did not know about.","TWN":"而且很多修練的地方大人們都找不到。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"네. 꽤 재밌게 놀았었죠.","JPN":"はい。大変楽しく遊びました。","ENG":"Yes. We had quite some fun.","TWN":"沒錯，所以我們玩得很開心。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"마음 놓고 누워 있기도 했고, 어른들 눈치 안 보고 크게 웃기도 했지.","JPN":"何の心配もなく寝転んだり、大人の目を気にせず大笑いもしたわね。","ENG":"We would lie down and relax, or laugh out loud without worrying about the adults.","TWN":"躺著休息，不用顧忌大人的眼神，開懷大笑。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"서로 합을 주고받다가 머리에 큰 혹이 났던 일도 기억나는군요.","JPN":"一緒に修練して、頭に大きなこぶができたことも覚えています。","ENG":"I remember how I got a big bump on my head after training with you.","TWN":"還記得我們切磋時，不小心在頭上打出一個包。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"그, 그땐……! 치후유가 내 몸에 상처를 낼 수 없다면서 갑자기 검을 내렸잖아.","JPN":"あ、あの時は……！　千冬が私を傷つけることができないからっていきなり刀を下ろすから。","ENG":"Th-that's...! You lowered your sword saying how you could not make a scratch on my body.","TWN":"那，那時候……！千冬說不想傷到我，突然就收起劍。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"언니가 얼마나 놀랐는지 알아?","JPN":"私がどれだけ驚いたかわかる？","ENG":"Do you know how shocked I was?","TWN":"姊姊當時多驚訝你知道嗎？"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"그때 눈물을 참느라 혼났습니다.","JPN":"あの時、涙をこらえるのに必死でした。","ENG":"It was difficult to hold my tears in.","TWN":"我那時候忍眼淚忍得很辛苦呢。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"그건 미안하게 생각해……","JPN":"それは悪かったわね……","ENG":"I am sorry about that...","TWN":"那件事我一直感到很抱歉……"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"몰래 도시로 나갔던 것도 기억나는군요.","JPN":"こっそり街まで出たこともありましたね。","ENG":"I also remember sneaking out to the city.","TWN":"還記得我們偷偷溜到城裡去的事。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"그렇게 몰래 나가서 사 먹었던 빙수, 생각나십니까?","JPN":"そこで食べたかき氷のこと、覚えていますか？","ENG":"Do you remember the shaved ice we had after we snuck out?","TWN":"那次偷偷溜出去吃的刨冰，你還記得嗎？"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"아~ 내가 치후유 손을 잡고 강제로 끌고 간 날 말하는 거구나?","JPN":"あ～私が千冬の手を引いて無理やり出た日のことね。","ENG":"Oh! You mean when I took your hand and dragged you out?","TWN":"喔～你是說我硬拉著你的手去的那次嗎？"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"저는 언니를 지켜야 하니 무작정 따라갔습니다만.","JPN":"私は姉さんをお守りしなければならないので、何も考えずについて行ったのですが。","ENG":"I did follow you since I had to protect you.","TWN":"我只能跟著姊姊，因為我要保護你。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"그때 먹었던 빙수가 참으로 맛있었습니다.","JPN":"あの時食べたかき氷がとてもおいしかったのです。","ENG":"But the shaved ice we had was delicious.","TWN":"那次刨冰，真的很好吃。"},"stage":{"bg":"1THBIRTHDAY","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}}]`);export{e as default};